import unittest

class TestSolution(unittest.TestCase):
    def test_basic_example(self):
        self.assertEqual(count_visible_pairs([3, 1, 2, 4]), 5)

    def test_five_buildings(self):
        self.assertEqual(count_visible_pairs([5, 1, 3, 2, 4]), 7)

    def test_increasing(self):
        self.assertEqual(count_visible_pairs([1, 2, 3, 4]), 3)

    def test_hidden_decreasing(self):
        self.assertEqual(count_visible_pairs([4, 3, 2, 1]), 3)

    def test_hidden_single(self):
        self.assertEqual(count_visible_pairs([5]), 0)

    def test_hidden_empty(self):
        self.assertEqual(count_visible_pairs([]), 0)

    def test_hidden_two_buildings(self):
        self.assertEqual(count_visible_pairs([2, 1]), 1)
        self.assertEqual(count_visible_pairs([1, 2]), 1)

    def test_hidden_complex_eight(self):
        self.assertEqual(count_visible_pairs([10, 6, 8, 5, 3, 7, 2, 9]), 13)

    def test_hidden_three_all_visible(self):
        # All 3 pairs visible when middle is shortest
        self.assertEqual(count_visible_pairs([3, 1, 2]), 3)

    def test_hidden_valley_shape(self):
        self.assertEqual(count_visible_pairs([5, 3, 1, 4, 2, 6]), 9)

    def test_hidden_large_increasing(self):
        n = 100000
        heights = list(range(1, n + 1))
        self.assertEqual(count_visible_pairs(heights), n - 1)

    def test_hidden_large_decreasing(self):
        n = 100000
        heights = list(range(n, 0, -1))
        self.assertEqual(count_visible_pairs(heights), n - 1)

if __name__ == '__main__':
    unittest.main()
